import{_ as o,o as a,c as t,a2 as s}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"LLM/RAG 강의 41편을 VitePress /llm/ 섹션으로 임포트하기","description":"","frontmatter":{"slug":"llm-course-import","title":"LLM/RAG 강의 41편을 VitePress /llm/ 섹션으로 임포트하기","authors":[],"tags":["llm","rag","langchain","vitepress","content-migration","automation","spec-kit","tooling"],"created":"2026-06-03 15:40 (KST)","date":"2026-06-03T06:40:00.000Z"},"headers":[],"relativePath":"journal/2026-06-03-llm-course-import.md","filePath":"journal/2026-06-03-llm-course-import.md","lastUpdated":1781092690000}'),l={name:"journal/2026-06-03-llm-course-import.md"};function n(i,e,r,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[s('<p><code>../llm-main</code> 에 흩어져 있던 한국어 LLM/RAG 강의 시리즈(LangChain · Ollama · 임베딩 · RAG · LangGraph)를 현재 VitePress 사이트의 전용 <code>/llm/</code> 섹션으로 한 번의 명령에 임포트했다. Spec Kit 사이클(specify → clarify → plan → tasks → analyze → implement)을 그대로 타고 멱등 임포터를 만들었다.</p><h2 id="무엇을-옮겼나" tabindex="-1">무엇을 옮겼나 <a class="header-anchor" href="#무엇을-옮겼나" aria-label="Permalink to &quot;무엇을 옮겼나&quot;">​</a></h2><ul><li><strong>강의 본문</strong> <code>m*.md</code> 45편 중 <strong>41편 임포트</strong>, 본문이 0-byte 인 4편(m124~m127)은 스킵(예제 <code>.py</code> 만 있고 글이 없음).</li><li><strong>예제 코드</strong> <code>m*.py</code> 를 각 강의 페이지 <strong>말미에 &quot;전체 예제 코드&quot;</strong> 로 인라인 (41편 인라인, stem 1:1 매핑).</li><li><strong>이미지</strong> 13장을 <code>blog/llm/assets/</code> 로 복사.</li></ul><p><code>scripts/import-llm-course.mjs</code> (Node ESM, 의존 0) 한 벌로 변환·복사·사이드바 생성·<code>config.mts</code> 배선까지 한다. 선례인 <a href="./2026-06-02-hexo-blog-import">Hexo 임포터</a>와 같은 구조다.</p><h2 id="까다로웠던-지점-세-가지" tabindex="-1">까다로웠던 지점 세 가지 <a class="header-anchor" href="#까다로웠던-지점-세-가지" aria-label="Permalink to &quot;까다로웠던 지점 세 가지&quot;">​</a></h2><h3 id="_1-프런트매터가-아예-없다" tabindex="-1">1. 프런트매터가 아예 없다 <a class="header-anchor" href="#_1-프런트매터가-아예-없다" aria-label="Permalink to &quot;1. 프런트매터가 아예 없다&quot;">​</a></h3><p>원본 강의에는 VitePress 가 요구하는 <code>title</code>·작성일시 메타가 전혀 없었다. 제목은 본문 첫 헤딩에서 도출했는데, 형식이 제각각이었다:</p><ul><li>정상 <code># LangGraph로 …</code> (m107 이후)</li><li>섹션형 <code>### 💻 환경 구성</code> (m101~m106)</li><li><code>## 😮‍💨 개발 블로그 #11. XMLOutputParser …</code> (m111)</li></ul><p>이모지·<code>개발 블로그 #NN.</code> 접두·후행 공백을 정규화하는 규칙으로 통일했다. 구현 중 <strong><code>#</code> 기호를 너무 일찍 지워 <code>#11.</code> 접두 제거가 깨지는</strong> 순서 버그를 단위 테스트가 잡아줬다 — 접두 제거를 먼저, 잔여 마크다운 기호 제거를 나중으로.</p><p>작성일시는 <strong>강의 번호 순서대로 단조 증가하는 가상 시각</strong>(base + index 분)으로 합성했다. 정렬은 &quot;최신 먼저&quot;가 아니라 <strong>학습 순서(번호 오름차순)</strong> 로 둔 게 이 콘텐츠의 핵심 예외다(강의 시리즈니까).</p><h3 id="_2-이미지-경로가-실제와-어긋나-있었다" tabindex="-1">2. 이미지 경로가 실제와 어긋나 있었다 <a class="header-anchor" href="#_2-이미지-경로가-실제와-어긋나-있었다" aria-label="Permalink to &quot;2. 이미지 경로가 실제와 어긋나 있었다&quot;">​</a></h3><p>본문은 <code>![](app/static/101_1.png)</code> 로 가리키는데 실제 파일은 <code>static/101_1.png</code> 에 있었다(<code>app/</code> 접두가 실재하지 않음). 그대로 옮기면 전부 깨진다. 접두 <code>app/</code> 제거 단일 규칙으로 해소하고 <code>./assets/</code> 상대 링크로 재작성했다.</p><h3 id="_3-예제-코드-안에-코드펜스가-들어-있었다" tabindex="-1">3. 예제 코드 안에 코드펜스가 들어 있었다 <a class="header-anchor" href="#_3-예제-코드-안에-코드펜스가-들어-있었다" aria-label="Permalink to &quot;3. 예제 코드 안에 코드펜스가 들어 있었다&quot;">​</a></h3><p><code>m135.py</code> 가 문자열로 <code>```mermaid</code> 를 품고 있어서, 예제를 그냥 <code>```python</code> 로 감싸면 펜스가 깨진다. 코드 내부의 가장 긴 백틱 런보다 한 칸 긴 펜스(여기선 4백틱)를 동적으로 골라 감쌌다.</p><h2 id="결과" tabindex="-1">결과 <a class="header-anchor" href="#결과" aria-label="Permalink to &quot;결과&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lessons:  41 imported, 4 skipped (empty)</span></span>\n<span class="line"><span>images:   13 copied, 0 missing</span></span>\n<span class="line"><span>examples: 41 inlined, 4 orphaned</span></span>\n<span class="line"><span>sidebar:  41 items → llm-sidebar.mts (번호 오름차순)</span></span></code></pre></div><ul><li><code>npm run build</code>(VitePress strict) <strong>통과</strong> — 깨진 링크·Vue 충돌 0.</li><li>2회 연속 실행 산출물 <strong>바이트 동일</strong>(멱등) — 원본에 강의가 추가되면 다시 돌리면 된다.</li><li>상단 내비 <strong>&quot;학습 가이드 → LLM 강의&quot;</strong> → <code>/llm/</code>.</li></ul><p>원본 <code>../llm-main</code> 은 한 글자도 건드리지 않는다(읽기 전용). 노트북·CSV·벡터DB· 운영 스크립트는 <code>m\\d+</code> 패턴 불일치로 자동 제외된다. 자세한 규약은 <code>specs/012-llm-course-import/</code>.</p>',18)])])}const h=o(l,[["render",n]]);export{u as __pageData,h as default};
